    $points = Order::updateCustomerPoints($data, $chainID);
    if ($points["status"] == true) {
        return response()->json($points,201,[],JSON_NUMERIC_CHECK);    
    }else{
        return response()->json($points,422,[],JSON_NUMERIC_CHECK);
    }

}

public function creditSettlement(Request $request){

