    $orderIDList = $credit["orderIDList"];
    if ($credit["status"] == true) {
        $queueNumber1 = queueNumber($chainID);
        $globalQueue = queueNumber('global');
        $job1 = (new GlobalOrderJobSettle($chainID,$storeID,$orderIDList,$orderPaymentInsertArray,$orderPaymentUpdateArray))->onQueue("$globalQueue");
        $this->dispatch($job1);

        $listOfChainsTable = Constants::getGlobalTableName("listOfChains");
        $getChainDetail = convertToArray(DB::table($listOfChainsTable)->SELECT('enableZohoIntegration')->where('chainID',$chainID)->get());
        if(!empty($getChainDetail) && $getChainDetail[0]['enableZohoIntegration']==1){
            $dataArray = array();
