             $orderArray[$orderDetails[$i]['orderID']."_totalChargeValue"] = $orderDetails[$i]['totalChargeValue'];
             if($orderArray[$orderDetails[$i]['orderID']."_paymentStatus"] == "PAID"){
                 array_push($paidOrders,$orderDetails[$i]['orderID']);
             }
         }

        //  if(!empty($paidOrders)){
        //      $status['status'] = false;
        //      $status['message'] = "Order Already Paid";
        //      $status['orderIDs'] = $paidOrders;
        //      return $status;
