     public static function fetchCreditNote($dataArray,$thirdPartyChainID){

        $chainID = $dataArray['chainID'];
        $storeID = $dataArray['storeID'];
        $phone = $dataArray['customerPhone'];

        $customersTable = Constants::getChainTableName($chainID, 'customers');
        $creditPaymentSummaryTable = Constants::getChainTableName($chainID,'creditPaymentSummary');

        $customerDetails = convertToArray(DB::table($customersTable)->where('phone',$phone)->where('isActive',1)->get());

        if(empty($customerDetails)){
            $status['status'] = false;
            $status['message'] = "No customer Found";
            return $status;
        }

        $customerID = $customerDetails[0]['customerID'];

        $creditNoteIDs = convertToArray(DB::table($creditPaymentSummaryTable)->where('customerID',$customerID)->whereRaw('status = "ACTIVE" AND creditNoteID != 0')->select('creditNoteID')->get());

        $status['status'] = true;
        $status['creditNotes'] = $creditNoteIDs;
        return $status;
     }

     public static function cancelPendingSettlement($dataArray,$thirdPartyChainID){

        $chainID = $dataArray['chainID'];
        $storeID = $dataArray['storeID'];
        $pendingSettlementID = $dataArray['pendingSettlementID'];

        $dataArray['thirdPartyChainID'] = $thirdPartyChainID;
        $checkAccess = self::checkApiAccess($dataArray);

        // if ($checkAccess["status"] == false) {
        //     return $checkAccess;
        // }

        $apiTrackerID = $checkAccess["apiTrackerID"];
        $status['apiTrackerID'] = $apiTrackerID;

        $pendingCreditSettlementsTable = Constants::getChainTableName($chainID,'pendingCreditSettlements');

        $pendingCreditSettlementDetails = convertToArray(DB::table($pendingCreditSettlementsTable)->where('ID',$pendingSettlementID)->where('settlementPaymentStatus','UNPAID')->where('isActive',1)->get());

        if(empty($pendingCreditSettlementDetails)){
            $status['status'] = false;
            $status['message'] = "No Pending Settlement Exists For pendingSettlementID : $pendingSettlementID";
            return $status;
        }

        DB::table($pendingCreditSettlementsTable)->where('ID',$pendingSettlementID)->where('settlementPaymentStatus','UNPAID')->where('isActive',1)->update(['isActive' => 0]);

        $status['status'] = true;
        $status['message'] = "Pending Settlement Has Been Cancelled Successfully";

        $status['apiTrackerID'] = $apiTrackerID;
        return $status;

    }

