    public static function createKotDetail($storeID, $dataArray)
    {
        $kotDetailArray = array();
        $cnt            = 0;

        if (!isset($dataArray["kotDetails"]) || empty($dataArray["kotDetails"])) {
          return $kotDetailArray;
        }

        $countOf = count($dataArray["kotDetails"]);
        for ($i = 0; $i < $countOf; $i++) {
            $kotDetailArray[$cnt]["orderID"]        = $dataArray["orderID"];
            $kotDetailArray[$cnt]["kotNumber"]      = keyCheck($dataArray["kotDetails"][$i], "kotNumber");
            $kotDetailArray[$cnt]["operation"]      = keyCheck($dataArray["kotDetails"][$i], "operation");
            $kotDetailArray[$cnt]["printCount"]     = keyCheck($dataArray["kotDetails"][$i], "printCount");
            $kotDetailArray[$cnt]["printRemarks"]   = keyCheck($dataArray["kotDetails"][$i], "printRemarks");
