    public static function createKotVoidDetail($storeID, $dataArray)
    {
        $responseArray   = array();
        $chainID = Constants::getChainID($storeID);
        $kotDetailsTable = Constants::getTableName($storeID, "kotVoidDetail");
        $chainKotDetailTable = Constants::getChainTableName($chainID,"kotVoidDetail");
        $kotVoidArray    = array();

        $timezone        = Constants::getChainTimezone($chainID);
        $count           = 0;

        if (!isset($dataArray["kotVoidDetails"]) || empty($dataArray["kotVoidDetails"])) {
          return $kotVoidArray;
        }

        for ($i = 0; $i < count($dataArray["kotVoidDetails"]); $i++) {
            $kotVoidArray[$count]["orderID"]       = $dataArray["kotVoidDetails"][$i]["orderID"];
            $kotVoidArray[$count]["orderSubID"]    = $dataArray["kotVoidDetails"][$i]["orderSubID"];
            $kotVoidArray[$count]["voidQuantity"]  = $dataArray["kotVoidDetails"][$i]["voidQuantity"];
            $kotVoidArray[$count]["productID"]     = $dataArray["kotVoidDetails"][$i]["productID"];
            $kotVoidArray[$count]["sizeVariantID"] = $dataArray["kotVoidDetails"][$i]["variantID"];
            $kotVoidArray[$count]["productName"]   = $dataArray["kotVoidDetails"][$i]["productName"];
            $kotVoidArray[$count]["sizeName"]      = $dataArray["kotVoidDetails"][$i]["variantName"];
            $kotVoidArray[$count]["modifiersList"] = isset($dataArray["kotVoidDetails"][$i]["modifiersList"])?$dataArray["kotVoidDetails"][$i]["modifiersList"]:NULL;
            $kotVoidArray[$count]["voidTimeLocal"] = $dataArray["kotVoidDetails"][$i]["voidTimeLocal"];

            if(!isset($dataArray["kotVoidDetails"][$i]["kotNumber"]))
                $kotVoidArray[$count]["kotNumber"] = -1;
            else
            $kotVoidArray[$count]["kotNumber"]     = $dataArray["kotVoidDetails"][$i]["kotNumber"];

            // if(!isset($dataArray["kotVoidDetails"][$i]["invoiceNumber"]))
            //     $dataArray["kotVoidDetails"][$i]["invoiceNumber"] = 0;
            $kotVoidArray[$count]["timezone"] = $timezone;
            $kotVoidArray[$count]["voidTimeUTC"]   = localToUTC($dataArray["kotVoidDetails"][$i]["voidTimeLocal"], $timezone);
            $kotVoidArray[$count]["voidRemarks"]   = $dataArray["kotVoidDetails"][$i]["voidRemarks"];
            $kotVoidArray[$count]["userName"]      = $dataArray["kotVoidDetails"][$i]["userName"];
            // $kotVoidArray[$count]["invoiceNumber"]      = $dataArray["kotVoidDetails"][$i]["invoiceNumber"];
            $kotVoidArray[$count]["productValue"]      = $dataArray["kotVoidDetails"][$i]["productValue"];

            $count++;
        }

        DB::transaction(function() use ($kotVoidArray, $kotDetailsTable,$chainKotDetailTable, $storeID)
        {
            for ($j = 0; $j < count($kotVoidArray); $j++) {
                try {
                DB::table($kotDetailsTable)->insert($kotVoidArray[$j]);
                $kotVoidArray[$j]["storeID"] = $storeID;
                DB::table($chainKotDetailTable)->insert($kotVoidArray[$j]);
                } catch (\Throwable $e) {
                    Log::error("Error while storing kot void detail. Store: ".$storeID. " detail ". json_encode($kotVoidArray[$j]));
					// Send to Sentry
					try {
						Log::info("Sending error to sentry");
						if (env("APP_ENV") == "production") {
							app('sentry')->captureException($e);
						}
					} catch (\Throwable $th) {
						// 
					}
                }
            }
        });

        $responseArray["status"] = true;
        $responseArray["data"] = $kotVoidArray;
        return $responseArray;
    }


