    $accountCount = 0;
    $temp         = array();

    $accountingArray = array();
    $x               = self::readExchangeOrderID($storeID, $orderId, "ACC_CARD_RECD");
    $y               = self::readExchangeOrderID($storeID, $orderId, "ACC_CASH_RECD");
    $z               = self::readExchangeOrderID($storeID, $orderId, "ACC_OTHER_RECD");

    if ($x + $y + $z <= 0) {
        return $accountingArray;
    }

