            $accountingArray[$accountCount]["transactionQuantity"]  = $reverseOrderArray["refundsList"][$i]["voidQuantity"];
            $accountingArray[$accountCount]["accountType"] = $reverseOrderArray["refundsList"][$i]["accountList"][$j]["accountType"];
            if ($accountingArray[$accountCount]["accountType"] == 'ACC_CREDIT_SALE') {
                $getCustomerID = convertToArray(DB::table($orderSummaryTable)->where('orderID', $orderId)->select('customersIDs')->get());
