                $accountingArray[$accountCount]["accountID"]   = $accountID;
                $accountingArray[$accountCount]["accountName"] = $accountName;

            }else{
                $accountingArray[$accountCount]["accountID"]   = $reverseOrderArray["refundsList"][$i]["accountList"][$j]["accountID"];
                $accountingArray[$accountCount]["accountName"] = $reverseOrderArray["refundsList"][$i]["accountList"][$j]["accountName"];

            }
            if ($accountingArray[$accountCount]["accountType"] == 'ACC_DISCOUNT') {
                $accountingArray[$accountCount]["credit"]       = $reverseOrderArray["refundsList"][$i]["accountList"][$j]["amount"];
                $accountingArray[$accountCount]["debit"]      = 0.0000;

            }else{
                $accountingArray[$accountCount]["debit"]       = $reverseOrderArray["refundsList"][$i]["accountList"][$j]["amount"];
                $accountingArray[$accountCount]["credit"]      = 0.0000;

            }

            $accountingArray[$accountCount]["transactionTypeID"] = "TRN_ORDER_CANCEL";
            $accountingArray[$accountCount]["exchange"]          = $accountingArray[$accountCount]["debit"] - $accountingArray[$accountCount]["credit"];

            $accountingArray[$accountCount]["transactionTimeLocal"] = $reverseOrderArray["refundSettledTime"];
            $accountingArray[$accountCount]["transactionTimeUTC"]   = localtoUTC($accountingArray[$accountCount]["transactionTimeLocal"], $accountingArray[$accountCount]["timezone"]);
            $accountingArray[$accountCount]["accountLogTimeLocal"]   = $accountLogTimeLocal;
            $accountingArray[$accountCount]["accountLogTimeUTC"]   = localtoUTC($accountingArray[$accountCount]["accountLogTimeLocal"], $accountingArray[$accountCount]["timezone"]);
            $accountingArray[$accountCount]["transactionUser"]   = $reverseOrderArray['voidUserName'];

            $accountCount++;
        }
    }
    return $accountingArray;
}

