public static function createPayments($storeID, $orderArray, $where)
{
    $orderId  = $orderArray["orderID"];
    $timezone = $orderArray["timezone"];
    $orderSummaryTable = Constants::getTableName($storeID, 'orderSummary');
    $customerAccountTable = Constants::getTableName($storeID, 'customerAccount');
    $accountingArray = array();

    $count = 0;
    if (isset($orderArray["paymentList"])) {
        for ($i = 0; $i < count($orderArray["paymentList"]); $i++) {
            $transactionTimeLocal = $orderArray["billSettledTimeLocal"];

            $accountingArray[$count]["orderID"]    = $orderId;
            $accountingArray[$count]["timezone"]   = $timezone;
            $accountingArray[$count]["orderSubID"] = -1;
            $accountingArray[$count]["posDate"]    = $orderArray["posDate"];


            $accountingArray[$count]["accountID"] = $orderArray["paymentList"][$i]["accountId"];
            if (isset($orderArray["paymentList"][$i]["accountType"]) && !empty($orderArray["paymentList"][$i]["accountType"])) {
                $accountingArray[$count]["accountType"] = $orderArray["paymentList"][$i]["accountType"];
            } else {
                $accType                                   = self::getAccountType($storeID, $accountingArray[$count]["accountID"]);
                $accountingArray[$count]["accountType"] = $accType;
            }

            if ($accountingArray[$count]["accountType"] == 'ACC_CREDIT_SALE') {
                $accountingArray[$count]["accountID"] = $orderArray["finalCustomerAccountID"];
                $accountingArray[$count]["accountName"] = $orderArray["finalCustomerAccountName"];
            }else{
                $accountingArray[$count]["accountName"] = $orderArray["paymentList"][$i]["accountName"];

            }
            if ($where == "Order Placed") {
                $accountingArray[$count]["debit"]  = $orderArray["paymentList"][$i]["amount"];
                $accountingArray[$count]["credit"] = 0.0000;
            } else {
                $accountingArray[$count]["debit"]  = 0.0000;
                $accountingArray[$count]["credit"] = $orderArray["paymentList"][$i]["amount"];
            }

            if (isset($orderArray["paymentList"][$i]["paymentType"]) && !empty($orderArray["paymentList"][$i]["paymentType"])) {
                $accountingArray[$count]["transactionPaymentType"] = $orderArray["paymentList"][$i]["paymentType"];
            }else{
                $accountingArray[$count]["transactionPaymentType"] = NULL;
            }

            if (isset($orderArray["paymentList"][$i]["cardType"]) && !empty($orderArray["paymentList"][$i]["cardType"])) {
                $accountingArray[$count]["transactionCardType"] = $orderArray["paymentList"][$i]["cardType"];
            }else{
                $accountingArray[$count]["transactionCardType"] = NULL;
            }                

            $accountingArray[$count]["exchange"]             = $accountingArray[$count]["debit"] - $accountingArray[$count]["credit"];
            // Hard Coded from globalTypeValues for TRN_ORDER
            $accountingArray[$count]["transactionTypeID"]    = "TRN_ORDER";
            $accountingArray[$count]["transactionTimeLocal"] = $transactionTimeLocal;
            $accountingArray[$count]["transactionTimeUTC"]   = localtoUTC($accountingArray[$count]["transactionTimeLocal"], $accountingArray[$count]["timezone"]);
            $count++;
        }
    }
    if (isset($orderArray["refundPayments"])) {
        for ($i = 0; $i < count($orderArray["refundPayments"]); $i++) {
            $transactionTimeLocal = $orderArray["refundSettledTime"];

            $accountingArray[$count]["orderID"]    = $orderId;
            $accountingArray[$count]["timezone"]   = $timezone;
            $accountingArray[$count]["orderSubID"] = -1;
            $accountingArray[$count]["posDate"]    = $orderArray["posDate"];


