public function createCreditSettlement(Request $request){

    $result = $request->getContent();

    if (isJson($result) == false) {
        $client = "Invalid Data";
        return response()->json($client, 422, [], JSON_NUMERIC_CHECK);
    }

    $data = convertToArray(json_decode($result));
    $thirdPartyChainID = $request->segment(4);
    $v = new V($data);
    $v->rule("required",array("chainID","storeID","customerPhone","referenceIDs","paymentMode"));
    if(!$v->validate()){
        $status["status"] = false;
        $status["message"] = $v->errors();
        return response()->json($status,422,[],JSON_NUMERIC_CHECK); 
    }
    $response = ThirdParty::createCreditSettlement($data,$thirdPartyChainID);

    if($response['status']){
        // api request tracker
        $trackerArray = array();
        $trackerArray['Authorization'] = $request->header("Authorization");
        $trackerArray['apiName'] = "createCreditSettlement";
        $trackerArray['apiPath'] = "/v1/thirdParty/{thirdPartyChainID}/createCreditSettlement";
        $trackerArray['apiMethod'] = "post";
        $trackerArray['remarks'] = $response['message'];
        $trackerArray['apiTrackerID'] = isset($response["apiTrackerID"])?$response["apiTrackerID"]:"NA";
        $trackerArray['thirdPartyChainID'] = $thirdPartyChainID;
        $trackerArray['storeID'] = isset($data["storeID"])?$data["storeID"]:0;
        $trackerArray['status'] = $response['status'];
        $trackerArray['requestPayload'] = json_encode($data);
        $trackerArray['responsePayload'] = json_encode($response);
        if (!$request->header('clientIP')) {
            $trackerArray['clientIP'] = $request->ip();
        }else{
            $trackerArray['clientIP'] = $request->header('clientIP');
        }
        $requestTracker = self::requestTracker($data["chainID"],$trackerArray);

        $beepkartResponse['status'] = true;
        $beepkartResponse['pendingSettlementIDs'] = $response['pendingSettlementIDs'];
        $beepkartResponse['message'] = "Credit Settlement Has Been Created Successfully";

        return response()->json($beepkartResponse,201,[],JSON_NUMERIC_CHECK);
    }else{
        return response()->json($response,422,[],JSON_NUMERIC_CHECK);
    }
}

