public static function customerInvoiceSettlement($dataArray){
     // check whether chain allow to share data with thirdParty chain
     $isAccessAllowed = self::checkStoreAccess($dataArray, 'CUSTOMER_DATA');
     if($isAccessAllowed['status'] == false){
         return $isAccessAllowed;
     }

     $chainID = $dataArray['chainID'];
     $orderID = $dataArray['orderID'];
     $thirdPartyChainID = $dataArray['thirdPartyChainID'];
     $listOfChainsTable = Constants::getGlobalTableName("listOfChains");
     $listOfStoresTable = Constants::getGlobalTableName("listOfStores");
     $orderSummaryTable = Constants::getChainTableName($chainID,"orderSummary");
     $orderPaymentsTable = Constants::getChainTableName($chainID,"orderPayments");
     $usersTable = Constants::getGlobalTableName("users");
     $globalTypeValuesTable = Constants::getGlobalTableName("globalTypeValues");
     $accountIDsTable = Constants::getChainTableName($chainID,"accountIDs");
     $globalTypePaymentAccountIDMappingTable = Constants::getGlobalTableName("globalPaymentAccountMapping");
     $userStoreMapTable = Constants::getGlobalTableName("userStoreMap");
     $storeID = $dataArray['storeID'];
     $apiAccessArray = array();
     $apiAccessArray['thirdPartyChainID'] = $thirdPartyChainID;
     $apiAccessArray['storeID'] = $dataArray['storeID'];
     $apiAccessArray['chainID'] = $dataArray['chainID'];
     $apiAccessArray['checkStoreAccess'] = 1;
     $checkAccess = self::checkApiAccess($apiAccessArray,$chainID);
     if ($checkAccess["status"] == false) {
         return $checkAccess;
     }


     // get store detail
     $getStoreDetail = convertToArray(DB::table($listOfStoresTable)->select('chainID')->where('storeID',$storeID)->get());
     if(empty($getStoreDetail)){
         $status['status'] = false;
         $status['message'] = "invalid storeID";
         return$status;
     }

     if($getStoreDetail[0]['chainID'] != $dataArray['chainID']){
         $status['status'] = false;
         $status['message'] = "chainID and storeID not mapped";
         return $status;
     }

     if($dataArray['amount'] <= 0){
         $status['status'] = false;
         $status['message'] = "Settlement amount must be greater than 0";
         return $status;
     }
     $apiTrackerArray  = array();
     $apiTrackerID = $checkAccess["apiTrackerID"]; 
     $getOrderSummary = convertToArray(DB::table("$orderSummaryTable AS A")->leftJoin("$usersTable as B","B.userName",'=',"A.userName")->SElECT("A.*","B.ID as userID")->where('orderID',$orderID)->get());
     if(empty($getOrderSummary)){
         $status['status'] = false;
         $status['message'] = "invalid orderID";
         return $status;
     }
     if($getOrderSummary[0]['paymentStatus'] == 'PAID'){
         $status['status'] = false;
         $status['message'] = "This order already has been paid";
         return $status;
     }
     if($dataArray['amount'] > $getOrderSummary[0]['grossBill']){
         $status['status'] = false;
         $status['message'] = "Settlement amount should be less/equal than invoice amount";
         return $status;
     }

     // get credit sale balace 
     $getCreditSaleBalace = convertToArray(DB::table($orderPaymentsTable)->SElECT('amount')->where('orderID',$orderID)->where('paymentType','PAYMENT_CREDIT')->get());
     if(empty($getCreditSaleBalace)){
         $status['status'] = false;
         $status['message'] = "no credit for this order";
         return $status;
     }
     $creditBalance = $getCreditSaleBalace[0]['amount'];
     if($dataArray['amount'] > $creditBalance){
         $status['status'] = false;
         $status['message'] = "Settlement amount is less/equal than credit amount";
         return $status;
     }
     $getChainAccounts = convertToArray(DB::table($accountIDsTable)->get());
     $getPaymentTypes = convertToArray(DB::table($globalTypeValuesTable)->where("typeID",7)->get());
     $getPaymentAccounts = convertToArray(DB::table($globalTypePaymentAccountIDMappingTable)->get());
     $data = array();
     $data['customerID'] = $getOrderSummary[0]['customersIDs'];
     $data['storeID'] = $getOrderSummary[0]['storeID'];
     $data['orderID'] = $orderID;
     $data['userID'] = $getOrderSummary[0]['userID'];
     $data['posDate'] = $getOrderSummary[0]['posDate'];
     $data['totalAmountPaid'] = $dataArray['amount'];
     $data['billSettledTimeLocal'] = date('Y-m-d H:i:s');
     $data['timezone'] = $timezone = Constants::getChainTimezone($chainID);
     $data['deviceID'] = $getOrderSummary[0]['deviceID'];
     $orderIDArray = explode(',', $dataArray['orderID']);
     $data['orderIDArray'] = $orderIDArray;
     $paymentArray = array();       
     $tempArray = array();
     $paymentType2 = $dataArray['paymentType'];
     $key = array_search($paymentType2, array_column($getPaymentTypes, 'value'));
     if (!is_int($key)) {
       $status["status"] = false;
       $status["message"] = "Invalid payment type";
       return $status;
     }
     $paymentTypeID = $getPaymentTypes[$key]["ID"];
     $key1 = array_search($paymentTypeID, array_column($getPaymentAccounts, 'paymentTypeValueID'));
     $payAccType = $getPaymentAccounts[$key1]["accountTypeValueID"];
     $key2 = array_search($payAccType, array_column($getChainAccounts, 'accountTypeValueID'));
     $tempArray['paymentType'] = $paymentType2;
     $tempArray['amount'] = $dataArray['amount'];
     $tempArray['accountId'] = $getChainAccounts[$key2]["accountID"];
     $tempArray['accountName'] = $getChainAccounts[$key2]["accountName"];
     $tempArray['accountType'] = $paymentType2;
     if($dataArray['transactionID'] != ''){
         $tempArray['transactionID'] = $dataArray['transactionID'];
     }
     if($dataArray['cardType'] != ''){
         $tempArray['cardType'] = $dataArray['cardType'];
     }
     if($dataArray['lastFourDigits'] != ''){
         $tempArray['lastFourDigits'] = $dataArray['lastFourDigits'];
     }
     array_push($paymentArray, $tempArray);
     $data['paymentList'] = $paymentArray;
     $response = Order::creditSettlement($chainID,$data);
     if($response['status'] == true){
         $updateCustomerAccount = $response['orderSummaryUpdateArray'][0];
         $balance = $updateCustomerAccount['amountDue'];
         $orderPaybleAmount = $getOrderSummary[0]['grossBill'];
         $totalAmountPaid = $orderPaybleAmount - $balance;
         $paymentStatus = $response['orderSummaryUpdateArray'][0]['paymentStatus'];
         $status['status'] = true;
         $status['orderPaybleAmount'] = $orderPaybleAmount;
         $status['amountPaid'] = $totalAmountPaid;
         $status['amountDue'] = $balance > 0 ? $balance : 0;
         $status['paymentStatus'] = $paymentStatus;
         $status['apiTrackerID'] = $apiTrackerID;
     } else{
         $status['status'] = false;
         $status['message'] = $response;
     }

     //$status['data'] = $response;
     return $status;
